DO $$ DECLARE v_lesson_id uuid; BEGIN
  SELECT id INTO v_lesson_id FROM lessons WHERE module_id = 'a4ce8c6c-ea88-45fb-b590-05fb329347c3' AND order_index = 7;
  IF v_lesson_id IS NULL THEN
    INSERT INTO lessons (course_id, module_id, institution_id, title, order_index, content_type, content_url, is_required)
    VALUES ('6b4906f1-803b-40bb-8582-d591220e5d09', 'a4ce8c6c-ea88-45fb-b590-05fb329347c3', '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'Lesson 6: Six Key Ingredients to Successful Advocacy', 7, 'blocks', '', true)
    RETURNING id INTO v_lesson_id;
  END IF;
  DELETE FROM lesson_blocks WHERE lesson_id = v_lesson_id;
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/advocacy-line-inverted-icon-free-vector_u8n3zu.jpg","caption":"<p style=\"text-align: left\"><strong>Overview:</strong></p><p style=\"text-align: left\">Successful advocacy means knowing what needs to be accomplished and being <u>realistic</u> in your expectations. It requires careful planning and strategic thinking. We have provided six ingredients to successful advocacy in this lesson to help you execute your advocacy initiative effectively.</p>"}],"mode":"slider"}'::jsonb, 0, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'image_gallery', '', '{"images":[{"url":"fit_content_assets/ingredient_n96pg7_sw7nly.jpg","caption":"<p style=\"text-align: left\"><strong>6 Key Ingredients to Successful Advocacy:</strong></p><ol><li><p style=\"text-align: left\"><strong>Identify and Define the Issue</strong></p></li><li><p style=\"text-align: left\"><strong>Be Passionate About the Issue</strong></p></li><li><p style=\"text-align: left\"><strong>Engage the People Affected by the Issue</strong></p></li><li><p style=\"text-align: left\"><strong>Engage with Policy Makers or Administrators</strong></p></li><li><p style=\"text-align: left\"><strong>Present One Ask at a Time</strong></p></li><li><p style=\"text-align: left\"><strong>Follow up Persistently</strong></p></li></ol>"}],"mode":"slider"}'::jsonb, 1, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Identify and Define the Issue', '{"html":"<p>Identify and define the advocacy issue to help create a focused and compelling message, and prioritize and allocate resources effectively. To engage others in supporting the advocacy issue, you must also be convincing that the issue is worth supporting and to demonstrate this, you must do your homework (research) to demonstrate your knowledge of the issue. It is important to identify target audiences, develop clear messages, and choose appropriate communication channels to maximize the impact of advocacy efforts.</p>\n<img src=\"fit_content_assets/picture_with_donnell_gtatud_omgktw.jpg\" alt=\"\" />\n<p>You might encounter people asking questions like, \"Why are you passionate about this cause?\" or \"What is your story?\" or \"What is your connection to this issue?\" Essentially, they want to understand <u>why you are dedicated to this cause</u>. They seek to know why they should support you, providing you with an excellent opportunity to engage them effectively.</p>","media":[{"type":"image","url":"fit_content_assets/picture_with_donnell_gtatud_omgktw.jpg"}],"mode":"scrolling"}'::jsonb, 2, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 3, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 4, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Be Passionate About the Issue', '{"html":"<p>Once you have defined the issue, the next step is to infuse energy (passion) into the process. To drive an advocacy initiative, you must be passionate about it.</p><p>Patient advocates with personal connections to the advocacy issue are usually passionate about the issue and this is an important ingredient to achieve success in advocacy. However, passion alone is not enough. Passion needs to be honed with strong advocacy skill sets which can be built through training and volunteering among other opportunities.</p>\n<img src=\"fit_content_assets/passionate_advocates_qkke6c.jpg\" alt=\"\" />\n<p></p>","media":[{"type":"image","url":"fit_content_assets/passionate_advocates_qkke6c.jpg"}],"mode":"scrolling"}'::jsonb, 5, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 6, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 7, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Engage the People Affected by the Issue', '{"html":"<p>Utilizing the stories of people with a connection to the issue you are advocating for is a priceless strategy to drive your advocacy initiative forward.</p><p></p><p>Stories that evoke human emotions will go a long way to drive support for your cause. Meet with those affected by the issue, listen to their stories, and what they would like to see accomplished.</p><p></p>\n<img src=\"fit_content_assets/story-_dzg8d7.jpg\" alt=\"\" />\n<p>Utilize your story (if applicable) and their stories to build support for the advocacy issue.</p>","media":[{"type":"image","url":"fit_content_assets/story-_dzg8d7.jpg"}],"mode":"scrolling"}'::jsonb, 8, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 9, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 10, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Engage with Policy Makers or Administrators', '{"html":"<p>While the advocacy goal is to drive a change in policy, it is important to know <u>when</u> and <u>how</u> to work with politicians and bureaucrats.</p><p>Working with Politicians: Politicians introduce bills and advocate for policy changes in legislative bodies.</p><p>Find the politician/s with a political will and/or empathy for your cause/issue from the <u>government of the day</u>, and work with them to drive the initiative. In addition, engage all political parties and be non-partisan in your approach.</p><p>When your advocacy work is hitting a brick wall, you may utilize the power of the opposition (such as engaging the health critic to get your initiative some attention with the government.</p>\n<img src=\"fit_content_assets/black_man_reading_a_document_wnekol.jpg\" alt=\"\" />\n<p>Working with Bureaucrats:  The bureaucrats are responsible for putting together (developing) and regulating policies in order to operationalize an approved ASK.</p>\n<p>Seek a face-to-face meeting with politicians and policy makers where possible, and attend the meeting with a well-written 1-2 page paper on your ASK that you can leave behind.</p>","media":[{"type":"image","url":"fit_content_assets/black_man_reading_a_document_wnekol.jpg"}],"mode":"scrolling"}'::jsonb, 11, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 12, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 13, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Present One Ask at a Time', '{"html":"<p>Patient advocates might have multiple ASKs/Needs that will benefit their community, however, there is a higher chance of success when a single ASK at a time is presented to the policy makers. Once that ASK is achieved, the next ASK may be presented.</p><p></p><p>Low Hanging Fruit: To build empathy of policy makers around your disease, start with a low hanging fruit ASK such as an Awareness Day Bill. During the debate of such a Bill, the policy makers debating such Bill will learn more about the disease, and possibly develop empathy for those affected by it.</p><p>With empathy built around the disease, patient advocates would be more successful in receiving their ASK and presenting future ASKs to the policymakers.</p>\n<img src=\"fit_content_assets/policy_maker_hltxnu.jpg\" alt=\"\" />\n<p></p>","media":[{"type":"image","url":"fit_content_assets/policy_maker_hltxnu.jpg"}],"mode":"scrolling"}'::jsonb, 14, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 15, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 16, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Be Persistent with Your ASK', '{"html":"<p>You might have heard that persistency is the name of the game. This could not be more true where advocacy is concerned.</p><p>You must recognize that your ASK or Advocacy issue is not the only item on the government''s or hospital administrator''s table. Note that:</p><p></p><ul><li><p>Politicians and policymakers are bombarded with numerous ASKs or presented issues</p></li><li><p>There is limited resources to support all ASKs or presented issues</p></li></ul>\n<img src=\"fit_content_assets/0001-2756633896717723470_e9l9w0.png\" alt=\"\" />\n<p>As such, seasoned advocates must:</p><ul><li><p>Be persistent in presenting and reiterating their ASKs with the engaged politician and/or policymakers,</p></li><li><p>Constantly review and improve their <u>engagement strategies</u> and never give up until the goal is accomplished.</p></li></ul>","media":[{"type":"image","url":"fit_content_assets/0001-2756633896717723470_e9l9w0.png"}],"mode":"scrolling"}'::jsonb, 17, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 18, true, 1, '{}'::jsonb);
